grader.tests:
orig = {'a':[{'b':1}], 'x':2}
out = apply_patch(orig, [{'op':'replace','path':'/a/0/b','value':3}, {'op':'add','path':'/a/1','value':{'b':4}}, {'op':'remove','path':'/x'}])
assert out == {'a':[{'b':3},{'b':4}]}, out
assert orig == {'a':[{'b':1}], 'x':2}
assert apply_patch({'a':{}}, [{'op':'add','path':'/a/c','value':5}]) == {'a':{'c':5}}

def norm(comps): return sorted([tuple(sorted(c)) for c in comps])
g = {1:[2], 2:[3,4], 3:[1], 4:[5], 5:[4], 6:[5]}
assert norm(strongly_connected_components(g)) == [(1,2,3),(4,5),(6,)]
assert norm(strongly_connected_components({'a':[]})) == [('a',)]
assert norm(strongly_connected_components({'a':['b']})) == [('a',),('b',)]
